-- DNA v1.0.6 - Tables only first, policies later
DO $$ BEGIN CREATE TYPE app_role AS ENUM ('user', 'moderator', 'admin'); EXCEPTION WHEN duplicate_object THEN null; END $$;
DO $$ BEGIN CREATE TYPE opportunity_status AS ENUM ('draft', 'active', 'paused', 'closed', 'archived'); EXCEPTION WHEN duplicate_object THEN null; END $$;
DO $$ BEGIN CREATE TYPE opportunity_visibility AS ENUM ('public', 'network_only', 'private'); EXCEPTION WHEN duplicate_object THEN null; END $$;
DO $$ BEGIN CREATE TYPE contribution_type AS ENUM ('time', 'expertise', 'network', 'capital'); EXCEPTION WHEN duplicate_object THEN null; END $$;
DO $$ BEGIN CREATE TYPE application_status AS ENUM ('pending', 'reviewing', 'accepted', 'rejected', 'withdrawn'); EXCEPTION WHEN duplicate_object THEN null; END $$;
CREATE TABLE IF NOT EXISTS skills (id UUID DEFAULT gen_random_uuid() PRIMARY KEY, name TEXT UNIQUE NOT NULL, category TEXT, created_at TIMESTAMPTZ DEFAULT NOW());
CREATE TABLE IF NOT EXISTS causes (id UUID DEFAULT gen_random_uuid() PRIMARY KEY, name TEXT UNIQUE NOT NULL, description TEXT, icon TEXT, created_at TIMESTAMPTZ DEFAULT NOW());
CREATE TABLE IF NOT EXISTS organizations (id UUID DEFAULT gen_random_uuid() PRIMARY KEY, name TEXT NOT NULL, slug TEXT UNIQUE NOT NULL, description TEXT, logo_url TEXT, website TEXT, country_id UUID REFERENCES countries(id), owner_user_id UUID NOT NULL REFERENCES profiles(id), verified BOOLEAN DEFAULT false, verified_at TIMESTAMPTZ, created_at TIMESTAMPTZ DEFAULT NOW(), updated_at TIMESTAMPTZ DEFAULT NOW(), deleted_at TIMESTAMPTZ);
CREATE TABLE IF NOT EXISTS opportunities (id UUID DEFAULT gen_random_uuid() PRIMARY KEY, org_id UUID NOT NULL REFERENCES organizations(id), created_by UUID NOT NULL REFERENCES profiles(id), title TEXT NOT NULL, description TEXT NOT NULL, requirements TEXT, contribution_types contribution_type[] NOT NULL, skills_needed UUID[] DEFAULT '{}', causes UUID[] DEFAULT '{}', location TEXT, time_commitment_hours INTEGER, duration_months INTEGER, start_date DATE, status opportunity_status DEFAULT 'draft', visibility opportunity_visibility DEFAULT 'public', max_applicants INTEGER, current_applicants INTEGER DEFAULT 0, views_count INTEGER DEFAULT 0, applications_count INTEGER DEFAULT 0, created_at TIMESTAMPTZ DEFAULT NOW(), updated_at TIMESTAMPTZ DEFAULT NOW(), published_at TIMESTAMPTZ, closed_at TIMESTAMPTZ, deleted_at TIMESTAMPTZ);
CREATE TABLE IF NOT EXISTS opportunity_applications (id UUID DEFAULT gen_random_uuid() PRIMARY KEY, opportunity_id UUID NOT NULL REFERENCES opportunities(id), applicant_id UUID NOT NULL REFERENCES profiles(id), cover_letter TEXT, proposed_contribution_type contribution_type NOT NULL, proposed_hours_per_month INTEGER, status application_status DEFAULT 'pending', reviewed_by UUID REFERENCES profiles(id), reviewed_at TIMESTAMPTZ, review_notes TEXT, created_at TIMESTAMPTZ DEFAULT NOW(), updated_at TIMESTAMPTZ DEFAULT NOW(), withdrawn_at TIMESTAMPTZ, UNIQUE(opportunity_id, applicant_id));
CREATE TABLE IF NOT EXISTS opportunity_contributions (id UUID DEFAULT gen_random_uuid() PRIMARY KEY, application_id UUID UNIQUE REFERENCES opportunity_applications(id), opportunity_id UUID NOT NULL REFERENCES opportunities(id), contributor_id UUID NOT NULL REFERENCES profiles(id), contribution_type contribution_type NOT NULL, description TEXT, hours_contributed INTEGER DEFAULT 0, verified_by UUID REFERENCES profiles(id), verified_at TIMESTAMPTZ, verification_notes TEXT, started_at TIMESTAMPTZ DEFAULT NOW(), completed_at TIMESTAMPTZ, created_at TIMESTAMPTZ DEFAULT NOW(), updated_at TIMESTAMPTZ DEFAULT NOW());
CREATE TABLE IF NOT EXISTS user_roles (id UUID DEFAULT gen_random_uuid() PRIMARY KEY, user_id UUID NOT NULL REFERENCES profiles(id), role app_role NOT NULL DEFAULT 'user', granted_by UUID REFERENCES profiles(id), granted_at TIMESTAMPTZ DEFAULT NOW(), UNIQUE(user_id, role));
CREATE OR REPLACE FUNCTION has_role(_user_id UUID, _role app_role) RETURNS BOOLEAN LANGUAGE sql STABLE SECURITY DEFINER SET search_path = public AS $$ SELECT EXISTS (SELECT 1 FROM user_roles WHERE user_id = _user_id AND role = _role); $$;
CREATE OR REPLACE FUNCTION owns_organization(_user_id UUID, _org_id UUID) RETURNS BOOLEAN LANGUAGE sql STABLE SECURITY DEFINER SET search_path = public AS $$ SELECT EXISTS (SELECT 1 FROM organizations WHERE id = _org_id AND owner_user_id = _user_id); $$;
ALTER TABLE organizations ENABLE ROW LEVEL SECURITY;
ALTER TABLE opportunities ENABLE ROW LEVEL SECURITY;
ALTER TABLE opportunity_applications ENABLE ROW LEVEL SECURITY;
ALTER TABLE opportunity_contributions ENABLE ROW LEVEL SECURITY;
ALTER TABLE user_roles ENABLE ROW LEVEL SECURITY;
ALTER TABLE skills ENABLE ROW LEVEL SECURITY;
ALTER TABLE causes ENABLE ROW LEVEL SECURITY;